+    /// Verify that column-level CHECK constraints and column-level PRIMARY KEY
+    /// survive a VACUUM round-trip: the original DDL should be used rather than
+    /// reconstructed SQL that can lose constraints.
+    #[cfg(unix)]
+    #[test]
+    fn test_vacuum_preserves_column_level_check_constraints() {
+        let _serial = super::fsqlite_core_test_serializer();
+        let cx = Cx::new();
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("check_constraint_vacuum.db");
+        let db_str = db_path.to_string_lossy().into_owned();
+
+        let pager = Arc::new(
+            SimplePager::open_with_cx(&cx, UnixVfs::new(), &db_path, PageSize::DEFAULT)
+                .expect("open unix pager"),
+        );
+        let conn = Connection::open_with_env_and_pager(
+            db_str.clone(),
+            ConnectionEnv::default(),
+            PagerBackend::Unix(pager),
+        )
+        .expect("open forced-unix connection");
+
+        conn.execute("PRAGMA journal_mode = WAL;").unwrap();
+        conn.execute(
+            "CREATE TABLE items (
+                id TEXT PRIMARY KEY,
+                title TEXT NOT NULL CHECK(length(title) <= 100),
+                priority INTEGER NOT NULL DEFAULT 2 CHECK(priority >= 0 AND priority <= 4)
+            );",
+        )
+        .unwrap();
+        conn.execute(
+            "INSERT INTO items(id, title, priority) VALUES ('a', 'hello', 2);",
+        )
+        .unwrap();
+
+        // VACUUM should preserve the original DDL including CHECK constraints
+        conn.execute("VACUUM;").unwrap();
+        conn.close().unwrap();
+
+        // Verify with stock rusqlite: integrity check
+        let sqlite = rusqlite::Connection::open(&db_path).unwrap();
+        let integrity_check: String = sqlite
+            .query_row("PRAGMA integrity_check;", [], |row| row.get(0))
+            .unwrap();
+        assert_eq!(integrity_check, "ok");
+
+        // Verify the CHECK constraints are enforced after VACUUM
+        let result = sqlite.execute(
+            "INSERT INTO items(id, title, priority) VALUES ('b', 'x', 99)",
+            [],
+        );
+        assert!(
+            result.is_err(),
+            "CHECK(priority >= 0 AND priority <= 4) should reject priority=99 after VACUUM"
+        );
+
+        // Verify column-level CHECK on title
+        let long_title = "x".repeat(101);
+        let result = sqlite.execute(
+            "INSERT INTO items(id, title, priority) VALUES ('c', ?1, 2)",
+            [&long_title],
+        );
+        assert!(
+            result.is_err(),
+            "CHECK(length(title) <= 100) should reject title > 100 chars after VACUUM"
+        );
+
+        // Verify valid inserts still work
+        sqlite
+            .execute(
+                "INSERT INTO items(id, title, priority) VALUES ('d', 'valid', 3)",
+                [],
+            )
+            .unwrap();
+    }
+
